create table public.users (id uuid primary key references auth.users(id), email text not null, google_id text, role text check (role in ('candidate','employer','admin')) not null, created_at timestamptz default now());
create table public.candidate_profiles (user_id uuid primary key references public.users(id), name text, phone text, location text, region text, roles_wanted text, languages text, experience text, availability text, accommodation_needed boolean, preferred_contact text, whatsapp_number text, status text check(status in('new','reviewed','matched','placed','rejected')) default 'new', created_at timestamptz default now(), updated_at timestamptz default now());
create table public.employer_profiles (user_id uuid primary key references public.users(id), company_name text, contact_person text, phone text, city text, business_type text, hiring_needs text, status text check(status in('new','qualified','active','closed')) default 'new', created_at timestamptz default now(), updated_at timestamptz default now());
create table public.status_history (id bigint generated always as identity primary key, subject_type text not null, subject_id uuid not null, old_status text, new_status text not null, changed_by uuid, ts timestamptz default now());
alter table public.users enable row level security; alter table public.candidate_profiles enable row level security; alter table public.employer_profiles enable row level security; alter table public.status_history enable row level security;
create policy "read own user" on public.users for select using (auth.uid()=id); create policy "read own candidate profile" on public.candidate_profiles for select using(auth.uid()=user_id); create policy "update own candidate profile" on public.candidate_profiles for update using(auth.uid()=user_id) with check(auth.uid()=user_id); create policy "read own employer profile" on public.employer_profiles for select using(auth.uid()=user_id); create policy "update own employer profile" on public.employer_profiles for update using(auth.uid()=user_id) with check(auth.uid()=user_id); create policy "read own history" on public.status_history for select using(auth.uid()=subject_id);
-- Service role/admin automation creates profiles, changes status, and writes history; client roles never set status.
